reference_solution.javascript:
const data = require("fs").readFileSync(0, "utf8").split(/\s+/).filter(Boolean).map(Number);
let pos = 0;
const t = data[pos++];
const out = [];
for (let i = 0; i < t; i++) {
  const n = data[pos++];
  const target = data[pos++];
  const tokens = data.slice(pos, pos + n);
  pos += n;
  const seen = new Set();
  let ans = "NO";
  for (const tok of tokens) {
    if (seen.has(target - tok)) { ans = "YES"; break; }
    seen.add(tok);
  }
  out.push(ans);
}
console.log(out.join("\n"));
